def main():
    with open(DB_PATH, 'r') as f:
        db = json.load(f)

    existing_names = {c['name'].lower(): i for i, c in enumerate(db)}
    updated = 0
    added = 0

    # 1. Fill in bios for existing comedians
    for name, bio in EXISTING_BIOS.items():
        key = name.lower()
        if key in existing_names:
            idx = existing_names[key]
            if not db[idx].get('bio'):
                db[idx]['bio'] = bio
                updated += 1
        else:
            # Also check for case variations
            found = False
            for i, c in enumerate(db):
                if c['name'].lower() == key:
                    if not c.get('bio'):
                        c['bio'] = bio
                        updated += 1
                    found = True
                    break

    # 2. Add new top-tier comedians
    for comedian in NEW_TOP_TIER:
        key = comedian['name'].lower()
        if key not in existing_names:
            entry = {"name": comedian['name'], "bio": comedian['bio'], "venues": comedian.get('venues', [])}
            db.append(entry)
            existing_names[key] = len(db) - 1
            added += 1
        else:
            # Update bio if missing
            idx = existing_names[key]
            if not db[idx].get('bio') and comedian.get('bio') and comedian['bio'] != 'See above':
                db[idx]['bio'] = comedian['bio']
                updated += 1

    # 3. Add new other-tier comedians
    for comedian in NEW_OTHER_TIER:
        key = comedian['name'].lower()
        if key not in existing_names:
            entry = {"name": comedian['name'], "bio": comedian['bio'], "venues": comedian.get('venues', [])}
            db.append(entry)
            existing_names[key] = len(db) - 1
            added += 1
        else:
            # Update bio if missing
            idx = existing_names[key]
            if not db[idx].get('bio') and comedian.get('bio'):
                db[idx]['bio'] = comedian['bio']
                updated += 1

    # Write back
    with open(DB_PATH, 'w') as f:
        json.dump(db, f, indent=2, ensure_ascii=False)

    print(f"Updated {updated} existing bios")
    print(f"Added {added} new comedians")
    print(f"Total comedians: {len(db)}")


if __name__ == '__main__':
    main()
